// Build-time loaders for the F2 dataset (generated by f2_predictions.export and
// the forward_eval / drift / promotion CLIs). Server components in a static
// export read these JSON files from disk at build time — no runtime fetches.

import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";

import type {
  CalibrationSummary,
  F2Data,
  ForwardEvalRound,
  ForwardEvalSeason,
  ModelHealth,
  ProbabilitiesRound,
  PromotionStatus,
  RoundDetail,
} from "@/types/f2";

const DATA_DIR = join(process.cwd(), "public", "data");

function readJson<T>(...segments: string[]): T | null {
  const path = join(DATA_DIR, ...segments);
  if (!existsSync(path)) return null;
  try {
    return JSON.parse(readFileSync(path, "utf-8")) as T;
  } catch {
    return null;
  }
}

function pad2(n: number): string {
  return String(n).padStart(2, "0");
}

let cache: F2Data | null = null;

export function getF2Data(): F2Data {
  if (cache) return cache;
  cache = readJson<F2Data>("f2.json");
  if (!cache) throw new Error("f2.json missing — run `python -m f2_predictions.export` first");
  return cache;
}

export function getRound(round: number): RoundDetail | null {
  return readJson<RoundDetail>("rounds", `round_${pad2(round)}.json`);
}

export function getProbabilities(round: number): ProbabilitiesRound | null {
  return readJson<ProbabilitiesRound>("probabilities", `round_${pad2(round)}.json`);
}

export function getCalibrationSummary(): CalibrationSummary | null {
  return readJson<CalibrationSummary>("calibration_summary.json");
}

export function getForwardEvalSeason(): ForwardEvalSeason | null {
  return readJson<ForwardEvalSeason>("forward_eval", "season.json");
}

export function getForwardEvalRounds(): ForwardEvalRound[] {
  const data = getF2Data();
  const rounds: ForwardEvalRound[] = [];
  for (let r = 1; r <= data.completedRounds; r++) {
    const rj = readJson<ForwardEvalRound>("forward_eval", `round_${pad2(r)}.json`);
    if (rj) rounds.push(rj);
  }
  return rounds;
}

export function getModelHealth(): ModelHealth | null {
  return readJson<ModelHealth>("model_health.json");
}

export function getPromotionStatus(): PromotionStatus | null {
  return readJson<PromotionStatus>("promotion_status.json");
}

// All calendar round numbers — for generateStaticParams on /race/[round].
export function allRoundNumbers(): number[] {
  return getF2Data().calendar.map((c) => c.round);
}

const BASE_PATH = process.env.NEXT_PUBLIC_BASE_PATH || "";

// basePath-aware asset URL for static export (driver headshots, brand, …).
export function asset(path: string): string {
  return `${BASE_PATH}${path.startsWith("/") ? path : `/${path}`}`;
}

// Team colours come from the data now (single source of truth in config.TEAMS).
// This map is only a fallback for older payloads / unknown teams.
const TEAM_COLORS: Record<string, string> = {
  "ART Grand Prix": "#3B3B3B",
  "Prema Racing": "#E2001A",
  "MP Motorsport": "#F47C20",
  DAMS: "#0090D0",
  "Campos Racing": "#1F3A93",
  "Invicta Racing": "#8E44AD",
  Hitech: "#101820",
  "Rodin Motorsport": "#00A19A",
  "Van Amersfoort Racing": "#FF5A00",
  Trident: "#0050A0",
  "AIX Racing": "#C0392B",
};

export function teamColor(team: string): string {
  return TEAM_COLORS[team] || "#1E9BD7";
}
